import anthropic
import json

client = anthropic.Anthropic()

# Simulated partial-observation environment
DATABASE = {
    "orders": [
        {"id": "1042", "status": "shipped",  "user_id": "u1"},
        {"id": "1043", "status": "pending",  "user_id": "u2"},
        {"id": "1044", "status": "returned", "user_id": "u1"},
    ],
    "users": {
        "u1": {"name": "Alice", "tier": "gold"},
        "u2": {"name": "Bob",   "tier": "standard"},
    },
}

def list_user_orders(user_id: str) -> str:
    orders = [o for o in DATABASE["orders"] if o["user_id"] == user_id]
    return json.dumps(orders)

def get_user_profile(user_id: str) -> str:
    return json.dumps(DATABASE["users"].get(user_id, {"error": "not found"}))

TOOLS = [
    {
        "name": "list_user_orders",
        "description": "List all orders for a specific user. Call this first to see what orders exist.",
        "input_schema": {
            "type": "object",
            "properties": {"user_id": {"type": "string"}},
            "required": ["user_id"],
        },
    },
    {
        "name": "get_user_profile",
        "description": "Get a user's profile including name and membership tier.",
        "input_schema": {
            "type": "object",
            "properties": {"user_id": {"type": "string"}},
            "required": ["user_id"],
        },
    },
]

DISPATCH = {
    "list_user_orders": list_user_orders,
    "get_user_profile": get_user_profile,
}

def run_agent_loop(user_message: str, max_rounds: int = 5) -> str:
    messages = [{"role": "user", "content": user_message}]

    for _ in range(max_rounds):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=(
                "You are a customer service agent. "
                "Use tools to observe the environment before answering. "
                "The user's ID is u1."
            ),
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})

        tool_calls = [b for b in resp.content if b.type == "tool_use"]
        if not tool_calls:
            # No more tool calls — agent has a final answer
            for block in resp.content:
                if block.type == "text":
                    return block.text
            return ""

        # Execute all tool calls and append results
        results = []
        for block in tool_calls:
            fn = DISPATCH[block.name]
            results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": fn(**block.input),
            })
        messages.append({"role": "user", "content": results})

    return "Max rounds reached without a final answer."

answer = run_agent_loop("Do I have any orders that have been returned?")
print(answer)
